//! Tests that verify our Rust kernel produces identical hashes for
//! the types of real Init constants, compared to Lean 4.25.2's C++ kernel.
//!
//! Source of truth: /r/tmp/lean4/kernelops.txt generated by KernelOps.lean

use lean4_kernel::name::Name;
use lean4_kernel::level::Level;
use lean4_kernel::expr::{Expr, BinderInfo};

// Helper: build Type u = Sort(succ(param u))
fn type_u(u: &str) -> Expr {
    Expr::mk_sort(&Level::mk_succ(&Level::mk_param(&Name::str(u))))
}

// ============================================================================
// Constants whose types we can construct by hand and verify hash
// ============================================================================

// CONST Nat kind=induct type_hash=3931117990 (Type = Sort 1)
#[test]
fn test_nat_type() {
    let ty = Expr::mk_sort(&Level::one()); // Type = Sort 1
    assert_eq!(ty.hash(), 3931117990);
}

// CONST Nat.zero kind=ctor type_hash=421340980 (Nat)
#[test]
fn test_nat_zero_type() {
    let ty = Expr::mk_const(&Name::str("Nat"), &[]);
    assert_eq!(ty.hash(), 421340980);
}

// CONST Nat.succ kind=ctor type_hash=2546708756 (Nat → Nat)
#[test]
fn test_nat_succ_type() {
    let nat = Expr::mk_const(&Name::str("Nat"), &[]);
    let ty = Expr::mk_pi(&Name::str("n"), BinderInfo::Default, &nat, &nat);
    assert_eq!(ty.hash(), 2546708756);
    assert_eq!(ty.approx_depth(), 1);
}

